// DJ OPUS - THE MEGA MIX
// One pattern to rule them all. YOU control the transitions.
// Breakdown -> Rise -> Drop all lives here. Ride the sliders.
setcps(138/60/4)

// === SECTION CONTROLS ===
let kickVol = slider(0, 0, 1, 0.01, "KICK")
let bassVol = slider(0, 0, 0.7, 0.01, "BASS")
let hatVol = slider(0, 0, 0.6, 0.01, "HATS")
let clapVol = slider(0, 0, 0.7, 0.01, "CLAP")
let acidVol = slider(0, 0, 0.7, 0.01, "ACID 303")
let leadVol = slider(0, 0, 0.5, 0.01, "LEAD")
let padVol = slider(0.3, 0, 0.6, 0.01, "PAD")
let sweepFilter = slider(1200, 200, 12000, 10, "FILTER SWEEP")

// KICK - four on the floor
let kick = s("bd").bank("RolandTR909")
  .gain(kickVol)
  .struct("x x x x")

// CLAP on 2 and 4
let clap = s("cp").bank("RolandTR909")
  .gain(clapVol)
  .struct("~ x ~ x")
  .room(0.25)

// OFFBEAT HATS
let hats = s("hh").bank("RolandTR909")
  .gain(hatVol)
  .struct("~ x ~ x ~ x ~ x")

// OPEN HAT accent
let oh = s("oh").bank("RolandTR909")
  .gain(hatVol)
  .struct("~ ~ ~ ~ ~ ~ x ~")

// DEEP BASS - rolling sawtooth with organic drift
let bass = note("<a2 a2 e2 e2 f2 f2 d2 d2>")
  .s("sawtooth")
  .cutoff(perlin.range(200, 1800).slow(8))
  .resonance(12)
  .decay(0.25)
  .sustain(0.08)
  .gain(bassVol)
  .struct("x ~ x x ~ x x ~")

// ACID 303 - squelchy
let acid = note("<a2 a2 c3 a2 e2 e2 g2 e2>")
  .s("sawtooth")
  .cutoff(sine.range(300, 3000).fast(2))
  .resonance(20)
  .decay(0.15)
  .sustain(0)
  .gain(acidVol)
  .struct("x x [x x] x x [~ x] x x")

// PAD SWEEP - galactic bed
let pad = note("<[a2,e3,a3] [e2,b2,e3] [f2,c3,f3] [d2,a2,d3]>".slow(2))
  .s("sawtooth")
  .cutoff(perlin.range(400, 2500).slow(16))
  .resonance(6)
  .attack(1.2)
  .decay(2)
  .sustain(0.5)
  .release(2)
  .gain(padVol)
  .room(0.9)
  .size(0.95)

// VOCAL PAD - sawtooth with vowel filter for diva texture
let vocalPad = note("<[a3,e4] [e3,b3] [f3,c4] [d3,a3]>".slow(2))
  .s("sawtooth")
  .vowel("<a e i o>".slow(4))
  .cutoff(sweepFilter)
  .resonance(8)
  .attack(0.8)
  .decay(1.5)
  .sustain(0.6)
  .release(2)
  .gain(padVol)
  .room(0.85)
  .size(0.9)

// LEAD - emotional supersaw
let lead = note("a4 ~ c5 ~ e5 ~ a5 e5 ~ c5 a4 ~ e4 ~ a4 ~")
  .s("sawtooth")
  .superimpose(x => x.add(0.08))
  .superimpose(x => x.add(-0.08))
  .cutoff(sweepFilter)
  .resonance(4)
  .decay(0.4)
  .sustain(0.15)
  .gain(leadVol)
  .delay(0.4)
  .delaytime(3/8)
  .delayfeedback(0.35)
  .room(0.6)
  .jux(rev)

// CRYSTAL FX - distant sparkle always present
let crystal = note("a5 ~ ~ ~ e5 ~ ~ ~".slow(2))
  .s("gm_fx_crystal")
  .gain(0.08)
  .delay(0.7)
  .delaytime(0.5)
  .delayfeedback(0.5)
  .room(1)

stack(kick, clap, hats, oh, bass, acid, pad, vocalPad, lead, crystal)
